<template>
  <div class="role-management">
    <el-card class="search-card">
      <el-form :model="searchForm" inline>
        <el-form-item label="用户名">
          <el-input
            v-model="searchForm.username"
            placeholder="请输入用户名"
            clearable
            @keyup.enter="handleSearch"
          />
        </el-form-item>
        <el-form-item label="角色">
          <el-select
            v-model="searchForm.role"
            placeholder="请选择角色"
            clearable
            style="width: 160px"
          >
            <el-option
              v-for="item in roleOptions"
              :key="item.value"
              :label="item.label"
              :value="item.value"
            />
          </el-select>
        </el-form-item>
        <el-form-item>
          <el-button type="primary" @click="handleSearch">
            <el-icon><Search /></el-icon>搜索
          </el-button>
          <el-button @click="handleReset">重置</el-button>
        </el-form-item>
      </el-form>
    </el-card>

    <el-card class="table-card">
      <template #header>
        <div class="card-header">
          <span class="title">用户列表</span>
          <el-button type="primary" @click="handleAdd">
            <el-icon><Plus /></el-icon>新增用户
          </el-button>
        </div>
      </template>

      <el-table
        :data="filteredUserList"
        stripe
        border
        v-loading="loading"
        style="width: 100%"
      >
        <el-table-column type="index" label="序号" width="60" align="center" />
        <el-table-column prop="username" label="用户名" min-width="120" />
        <el-table-column prop="realName" label="真实姓名" min-width="120" />
        <el-table-column prop="role" label="角色" min-width="120">
          <template #default="{ row }">
            <el-tag :type="getRoleType(row.role)">{{ row.role }}</el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="department" label="部门" min-width="120" />
        <el-table-column prop="status" label="状态" width="100" align="center">
          <template #default="{ row }">
            <el-switch
              v-model="row.status"
              :active-value="1"
              :inactive-value="0"
              :disabled="row.role === '系统管理员'"
              @change="handleStatusChange(row)"
            />
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="创建时间" min-width="160" />
        <el-table-column label="操作" width="280" fixed="right">
          <template #default="{ row }">
            <el-button type="primary" link @click="handleEdit(row)">
              <el-icon><Edit /></el-icon>编辑
            </el-button>
            <el-button type="warning" link @click="handleResetPassword(row)">
              <el-icon><Key /></el-icon>重置密码
            </el-button>
            <el-button type="danger" link @click="handleDelete(row)">
              <el-icon><Delete /></el-icon>删除
            </el-button>
          </template>
        </el-table-column>
      </el-table>

      <div class="pagination-wrapper">
        <el-pagination
          v-model:current-page="pagination.currentPage"
          v-model:page-size="pagination.pageSize"
          :page-sizes="[10, 20, 50, 100]"
          :total="pagination.total"
          layout="total, sizes, prev, pager, next, jumper"
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
        />
      </div>
    </el-card>

    <!-- 新增/编辑用户对话框 -->
    <el-dialog
      v-model="dialogVisible"
      :title="dialogTitle"
      width="500px"
      destroy-on-close
    >
      <el-form
        ref="formRef"
        :model="formData"
        :rules="formRules"
        label-width="80px"
      >
        <el-form-item label="用户名" prop="username">
          <el-input
            v-model="formData.username"
            placeholder="请输入用户名"
            :disabled="isEdit"
          />
        </el-form-item>
        <el-form-item label="真实姓名" prop="realName">
          <el-input v-model="formData.realName" placeholder="请输入真实姓名" />
        </el-form-item>
        <el-form-item label="角色" prop="role">
          <el-select v-model="formData.role" placeholder="请选择角色" style="width: 100%">
            <el-option
              v-for="item in roleOptions"
              :key="item.value"
              :label="item.label"
              :value="item.value"
            />
          </el-select>
        </el-form-item>
        <el-form-item label="部门" prop="department">
          <el-select v-model="formData.department" placeholder="请选择部门" style="width: 100%">
            <el-option
              v-for="item in departmentOptions"
              :key="item.value"
              :label="item.label"
              :value="item.value"
            />
          </el-select>
        </el-form-item>
        <el-form-item v-if="!isEdit" label="密码" prop="password">
          <el-input
            v-model="formData.password"
            type="password"
            placeholder="请输入密码"
            show-password
          />
        </el-form-item>
      </el-form>
      <template #footer>
        <el-button @click="dialogVisible = false">取消</el-button>
        <el-button type="primary" @click="handleSubmit" :loading="submitLoading">
          确定
        </el-button>
      </template>
    </el-dialog>

    <!-- 重置密码对话框 -->
    <el-dialog
      v-model="resetPasswordVisible"
      title="重置密码"
      width="400px"
    >
      <el-form
        ref="resetFormRef"
        :model="resetFormData"
        :rules="resetFormRules"
        label-width="80px"
      >
        <el-form-item label="新密码" prop="newPassword">
          <el-input
            v-model="resetFormData.newPassword"
            type="password"
            placeholder="请输入新密码"
            show-password
          />
        </el-form-item>
        <el-form-item label="确认密码" prop="confirmPassword">
          <el-input
            v-model="resetFormData.confirmPassword"
            type="password"
            placeholder="请再次输入新密码"
            show-password
          />
        </el-form-item>
      </el-form>
      <template #footer>
        <el-button @click="resetPasswordVisible = false">取消</el-button>
        <el-button type="primary" @click="handleResetPasswordSubmit" :loading="resetLoading">
          确定
        </el-button>
      </template>
    </el-dialog>
  </div>
</template>

<script setup lang="ts">
import { ref, reactive, computed, onMounted } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import type { FormInstance, FormRules } from 'element-plus'
import { Search, Plus, Edit, Delete, Key } from '@element-plus/icons-vue'

// 角色选项
const roleOptions = [
  { label: '系统管理员', value: '系统管理员' },
  { label: '生产主管', value: '生产主管' },
  { label: '质检员', value: '质检员' },
  { label: '操作员', value: '操作员' }
]

// 部门选项
const departmentOptions = [
  { label: '生产部', value: '生产部' },
  { label: '质检部', value: '质检部' },
  { label: '技术部', value: '技术部' },
  { label: '管理部', value: '管理部' }
]

// 角色权重（用于排序）
const roleWeight: Record<string, number> = {
  '系统管理员': 4,
  '生产主管': 3,
  '质检员': 2,
  '操作员': 1
}

// 用户类型定义
interface User {
  id: number
  username: string
  realName: string
  role: string
  department: string
  status: number
  createTime: string
  password?: string
}

// 搜索表单
const searchForm = reactive({
  username: '',
  role: ''
})

// 分页配置
const pagination = reactive({
  currentPage: 1,
  pageSize: 10,
  total: 0
})

// 加载状态
const loading = ref(false)
const submitLoading = ref(false)
const resetLoading = ref(false)

// 用户列表数据
const userList = ref<User[]>([])

// Mock 数据
const mockUserData: User[] = [
  {
    id: 1,
    username: 'admin',
    realName: '管理员',
    role: '系统管理员',
    department: '管理部',
    status: 1,
    createTime: '2024-01-15 09:30:00',
    password: 'admin123'
  },
  {
    id: 2,
    username: 'manager01',
    realName: '张主管',
    role: '生产主管',
    department: '生产部',
    status: 1,
    createTime: '2024-01-16 10:00:00',
    password: '123456'
  },
  {
    id: 3,
    username: 'inspector01',
    realName: '李质检',
    role: '质检员',
    department: '质检部',
    status: 1,
    createTime: '2024-01-17 11:30:00',
    password: '123456'
  },
  {
    id: 4,
    username: 'operator01',
    realName: '王操作',
    role: '操作员',
    department: '生产部',
    status: 1,
    createTime: '2024-01-18 14:00:00',
    password: '123456'
  },
  {
    id: 5,
    username: 'operator02',
    realName: '赵操作',
    role: '操作员',
    department: '生产部',
    status: 0,
    createTime: '2024-01-19 15:30:00',
    password: '123456'
  },
  {
    id: 6,
    username: 'inspector02',
    realName: '陈质检',
    role: '质检员',
    department: '质检部',
    status: 1,
    createTime: '2024-01-20 09:00:00',
    password: '123456'
  },
  {
    id: 7,
    username: 'manager02',
    realName: '刘主管',
    role: '生产主管',
    department: '生产部',
    status: 1,
    createTime: '2024-01-21 10:30:00',
    password: '123456'
  },
  {
    id: 8,
    username: 'operator03',
    realName: '孙操作',
    role: '操作员',
    department: '技术部',
    status: 1,
    createTime: '2024-01-22 13:00:00',
    password: '123456'
  }
]

// 获取角色标签类型
const getRoleType = (role: string) => {
  const typeMap: Record<string, string> = {
    '系统管理员': 'danger',
    '生产主管': 'warning',
    '质检员': 'success',
    '操作员': 'info'
  }
  return typeMap[role] || 'info'
}

// 过滤并排序后的用户列表
const filteredUserList = computed(() => {
  let result = [...userList.value]

  // 按角色权重排序
  result.sort((a, b) => roleWeight[b.role] - roleWeight[a.role])

  // 搜索过滤
  if (searchForm.username) {
    result = result.filter(user =>
      user.username.toLowerCase().includes(searchForm.username.toLowerCase())
    )
  }
  if (searchForm.role) {
    result = result.filter(user => user.role === searchForm.role)
  }

  // 分页
  pagination.total = result.length
  const start = (pagination.currentPage - 1) * pagination.pageSize
  const end = start + pagination.pageSize
  return result.slice(start, end)
})

// 搜索
const handleSearch = () => {
  pagination.currentPage = 1
}

// 重置搜索
const handleReset = () => {
  searchForm.username = ''
  searchForm.role = ''
  pagination.currentPage = 1
}

// 分页大小变化
const handleSizeChange = (val: number) => {
  pagination.pageSize = val
  pagination.currentPage = 1
}

// 页码变化
const handleCurrentChange = (val: number) => {
  pagination.currentPage = val
}

// 对话框相关
const dialogVisible = ref(false)
const isEdit = ref(false)
const dialogTitle = computed(() => isEdit.value ? '编辑用户' : '新增用户')
const formRef = ref<FormInstance>()

const formData = reactive({
  id: 0,
  username: '',
  realName: '',
  role: '',
  department: '',
  password: ''
})

const formRules: FormRules = {
  username: [
    { required: true, message: '请输入用户名', trigger: 'blur' },
    { min: 3, max: 20, message: '长度在 3 到 20 个字符', trigger: 'blur' }
  ],
  realName: [
    { required: true, message: '请输入真实姓名', trigger: 'blur' }
  ],
  role: [
    { required: true, message: '请选择角色', trigger: 'change' }
  ],
  department: [
    { required: true, message: '请选择部门', trigger: 'change' }
  ],
  password: [
    { required: true, message: '请输入密码', trigger: 'blur' },
    { min: 6, max: 20, message: '长度在 6 到 20 个字符', trigger: 'blur' }
  ]
}

// 新增用户
const handleAdd = () => {
  isEdit.value = false
  formData.id = 0
  formData.username = ''
  formData.realName = ''
  formData.role = ''
  formData.department = ''
  formData.password = ''
  dialogVisible.value = true
}

// 编辑用户
const handleEdit = (row: User) => {
  isEdit.value = true
  formData.id = row.id
  formData.username = row.username
  formData.realName = row.realName
  formData.role = row.role
  formData.department = row.department
  formData.password = ''
  dialogVisible.value = true
}

// 提交表单
const handleSubmit = async () => {
  if (!formRef.value) return

  await formRef.value.validate((valid) => {
    if (valid) {
      submitLoading.value = true

      setTimeout(() => {
        if (isEdit.value) {
          // 编辑
          const index = userList.value.findIndex(u => u.id === formData.id)
          if (index !== -1) {
            userList.value[index] = {
              ...userList.value[index],
              realName: formData.realName,
              role: formData.role,
              department: formData.department
            }
          }
          ElMessage.success('编辑成功')
        } else {
          // 新增
          const newUser: User = {
            id: Date.now(),
            username: formData.username,
            realName: formData.realName,
            role: formData.role,
            department: formData.department,
            status: 1,
            createTime: new Date().toLocaleString('zh-CN', {
              year: 'numeric',
              month: '2-digit',
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit',
              second: '2-digit'
            }).replace(/\//g, '-'),
            password: formData.password
          }
          userList.value.push(newUser)
          ElMessage.success('新增成功')
        }

        submitLoading.value = false
        dialogVisible.value = false
      }, 500)
    }
  })
}

// 删除用户
const handleDelete = (row: User) => {
  if (row.role === '系统管理员') {
    ElMessage.warning('系统管理员无法删除')
    return
  }

  ElMessageBox.confirm(
    `确定要删除用户 "${row.username}" 吗？`,
    '提示',
    {
      confirmButtonText: '确定',
      cancelButtonText: '取消',
      type: 'warning'
    }
  ).then(() => {
    userList.value = userList.value.filter(u => u.id !== row.id)
    ElMessage.success('删除成功')
  }).catch(() => {
    // 取消删除
  })
}

// 状态切换
const handleStatusChange = (row: User) => {
  if (row.role === '系统管理员') {
    ElMessage.warning('系统管理员无法被禁用')
    row.status = 1
    return
  }

  const statusText = row.status === 1 ? '启用' : '禁用'
  ElMessage.success(`用户 "${row.username}" 已${statusText}`)
}

// 重置密码相关
const resetPasswordVisible = ref(false)
const resetFormRef = ref<FormInstance>()
const currentResetUser = ref<User | null>(null)

const resetFormData = reactive({
  newPassword: '',
  confirmPassword: ''
})

const validateConfirmPassword = (rule: any, value: string, callback: Function) => {
  if (value !== resetFormData.newPassword) {
    callback(new Error('两次输入的密码不一致'))
  } else {
    callback()
  }
}

const resetFormRules: FormRules = {
  newPassword: [
    { required: true, message: '请输入新密码', trigger: 'blur' },
    { min: 6, max: 20, message: '长度在 6 到 20 个字符', trigger: 'blur' }
  ],
  confirmPassword: [
    { required: true, message: '请再次输入新密码', trigger: 'blur' },
    { validator: validateConfirmPassword, trigger: 'blur' }
  ]
}

// 重置密码
const handleResetPassword = (row: User) => {
  currentResetUser.value = row
  resetFormData.newPassword = ''
  resetFormData.confirmPassword = ''
  resetPasswordVisible.value = true
}

// 提交重置密码
const handleResetPasswordSubmit = async () => {
  if (!resetFormRef.value) return

  await resetFormRef.value.validate((valid) => {
    if (valid) {
      resetLoading.value = true

      setTimeout(() => {
        if (currentResetUser.value) {
          const index = userList.value.findIndex(u => u.id === currentResetUser.value!.id)
          if (index !== -1) {
            userList.value[index].password = resetFormData.newPassword
          }
        }
        ElMessage.success('密码重置成功')
        resetLoading.value = false
        resetPasswordVisible.value = false
      }, 500)
    }
  })
}

// 初始化数据
onMounted(() => {
  loading.value = true
  setTimeout(() => {
    userList.value = [...mockUserData]
    pagination.total = mockUserData.length
    loading.value = false
  }, 500)
})
</script>

